import{_ as n,o as t,c as i,ae as a}from"./chunks/framework.BeVX27ge.js";const d=JSON.parse('{"title":"Thực hành","description":"","frontmatter":{},"headers":[],"relativePath":"practice.md","filePath":"practice.md"}'),c={name:"practice.md"};function o(u,h,r,l,g,e){return t(),i("div",null,[...h[0]||(h[0]=[a('<h1 id="thuc-hanh" tabindex="-1">Thực hành <a class="header-anchor" href="#thuc-hanh" aria-label="Permalink to &quot;Thực hành&quot;">​</a></h1><blockquote><p>Luyện tập kỹ năng giao tiếp bán hàng qua các đoạn hội thoại mô phỏng với AI.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Thực hành (Practice) là tính năng cốt lõi của AI Coach. Bạn sẽ tương tác với một khách hàng ảo do AI điều khiển. Khách hàng này sẽ phản ứng chân thực dựa trên các thuộc tính được cài đặt (tuổi, nghề nghiệp, thu nhập, tính cách), xây dựng môi trường an toàn để bạn rèn luyện xử lý tình huống.</p><h2 id="cach-bat-đau" tabindex="-1">Cách Bắt đầu <a class="header-anchor" href="#cach-bat-đau" aria-label="Permalink to &quot;Cách Bắt đầu&quot;">​</a></h2><ul><li>Nút <strong>&quot;Bắt đầu Trò chuyện&quot;</strong> trên Bảng điều khiển.</li><li>Nút <strong>&quot;Thử lại&quot;</strong> hoặc <strong>&quot;Tiếp tục&quot;</strong> trong Lịch sử.</li></ul><hr><h2 id="chon-kich-ban" tabindex="-1">Chọn Kịch bản <a class="header-anchor" href="#chon-kich-ban" aria-label="Permalink to &quot;Chọn Kịch bản&quot;">​</a></h2><h3 id="kich-ban-ngau-nhien" tabindex="-1">Kịch bản Ngẫu nhiên <a class="header-anchor" href="#kich-ban-ngau-nhien" aria-label="Permalink to &quot;Kịch bản Ngẫu nhiên&quot;">​</a></h3><ul><li>Hệ thống tự động tạo một khách hàng ngẫu nhiên.</li><li>Dành cho luyện tập nhanh hoặc khi không có yêu cầu đặc thù.</li></ul><h3 id="kich-ban-tuy-chinh" tabindex="-1">Kịch bản Tùy chỉnh <a class="header-anchor" href="#kich-ban-tuy-chinh" aria-label="Permalink to &quot;Kịch bản Tùy chỉnh&quot;">​</a></h3><ul><li>Tự định nghĩa khách hàng theo nhu cầu (ví dụ: Khách thu nhập cao, đã kết hôn).</li><li>Hiển thị Cửa sổ cài đặt Chân dung Khách hàng.</li></ul><h3 id="thu-lai-tu-lich-su" tabindex="-1">Thử lại (Từ Lịch sử) <a class="header-anchor" href="#thu-lai-tu-lich-su" aria-label="Permalink to &quot;Thử lại (Từ Lịch sử)&quot;">​</a></h3><ul><li>Gặp lại khách hàng y hệt lần trước.</li><li>Thử nghiệm các chiến thuật khác nhau.</li></ul><h3 id="tiep-tuc-tu-lich-su" tabindex="-1">Tiếp tục (Từ Lịch sử) <a class="header-anchor" href="#tiep-tuc-tu-lich-su" aria-label="Permalink to &quot;Tiếp tục (Từ Lịch sử)&quot;">​</a></h3><ul><li>Tiếp tục trò chuyện dang dở.</li><li>Khách hàng sẽ nhớ mang máng những gì đã trao đổi.</li></ul><hr><h2 id="cai-đat-chan-dung-khach-hang" tabindex="-1">Cài đặt Chân dung Khách hàng <a class="header-anchor" href="#cai-đat-chan-dung-khach-hang" aria-label="Permalink to &quot;Cài đặt Chân dung Khách hàng&quot;">​</a></h2><p>Khi chọn &quot;Kịch bản Tùy chỉnh&quot;, bạn tự điền các thông tin. Các trường để trống sẽ được AI tự hoàn thiện.</p><ul><li><strong>Cơ bản</strong>: Tuổi, Giới tính, Tính cách (MBTI 16 loại), Thu nhập, Nghề nghiệp.</li><li><strong>Tính cách MBTI</strong>: Ảnh hưởng mạnh đến cách ra quyết định.</li><li><strong>Gia đình</strong>: Tình trạng hôn nhân, Số con, Tuổi &amp; Giới tính con cái.</li><li><strong>Mối quan hệ</strong>: Khách lạ hay người quen/người thân. Nếu là người quen, cần điền thêm &quot;Mô tả Mối quan hệ&quot;.</li></ul><hr><h2 id="giao-dien-tro-chuyen" tabindex="-1">Giao diện Trò chuyện <a class="header-anchor" href="#giao-dien-tro-chuyen" aria-label="Permalink to &quot;Giao diện Trò chuyện&quot;">​</a></h2><ul><li><strong>Trái</strong>: Thông tin chi tiết khách hàng.</li><li><strong>Giữa</strong>: Khung hội thoại chính.</li><li><strong>Trên</strong>: Lời mở đầu tình huống, Đồng hồ đo thời gian.</li><li><strong>Phải Trên</strong>: Nút &quot;Kết thúc trò chuyện&quot;.</li></ul><h3 id="quy-tac-an-toan" tabindex="-1">Quy tắc An toàn <a class="header-anchor" href="#quy-tac-an-toan" aria-label="Permalink to &quot;Quy tắc An toàn&quot;">​</a></h3><p>Trí tuệ nhân tạo được bảo vệ bằng cơ chế kiểm duyệt nội dung.</p><ul><li>Không gửi thông tin cá nhân thật (CCCD, SĐT...).</li><li>Không đăng nội dung phản cảm, vi phạm điều khoản chính sách. Nếu vi phạm, tin nhắn sẽ bị chặn.</li></ul><hr><h2 id="cac-giai-đoan-ban-hang" tabindex="-1">Các Giai đoạn Bán hàng <a class="header-anchor" href="#cac-giai-đoan-ban-hang" aria-label="Permalink to &quot;Các Giai đoạn Bán hàng&quot;">​</a></h2><p>Được thiết kế theo định nghĩa của quản trị viên (VD: Phá băng, Khám phá nhu cầu, Đưa ra giải pháp, Xử lý từ chối, Chốt sale).</p><ul><li>AI thực hiện đánh giá giai đoạn <strong>SAU KHI</strong> cuộc gọi kết thúc, không phải trong thời gian thực. Hãy tập trung xây dựng mạch hội thoại mượt mà!</li></ul><hr><h2 id="ket-thuc-tro-chuyen" tabindex="-1">Kết thúc Trò chuyện <a class="header-anchor" href="#ket-thuc-tro-chuyen" aria-label="Permalink to &quot;Kết thúc Trò chuyện&quot;">​</a></h2><ul><li><strong>Chủ động</strong>: Nhấn &quot;Kết thúc trò chuyện&quot; &gt; Xác nhận.</li><li><strong>Khách hàng yêu cầu dừng</strong>: Khi AI cho biết khách hàng muốn kết thúc cuộc gọi, hệ thống sẽ bật lên lựa chọn &quot;Cố gắng tiếp tục&quot; hoặc &quot;Chấp nhận kết thúc&quot;.</li></ul><p>Sau đó, hệ thống sẽ tự động khởi tạo Báo cáo Đánh giá.</p>',34)])])}const q=n(c,[["render",o]]);export{d as __pageData,q as default};
